import React from "react";
import { Link, useNavigate } from "react-router-dom";
import { Avatar, Button } from "@mui/material";

export default function Navbar() {
  const navigate = useNavigate();
  const role = localStorage.getItem("role");
  const token = localStorage.getItem("token");

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("role");
    navigate("/login");
  };

  let avatarLetter = "U"; // default
  if (role === "admin") avatarLetter = "A";
  else if (role === "rider") avatarLetter = "R";
  else if (role === "user") avatarLetter = "U";

  return (
    <nav
      style={{
        padding: "12px 20px",
        borderBottom: "1px solid #ddd",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
      }}
    >
      <Link to="/" style={{ fontWeight: "bold", fontSize: 18 }}>
        Rider App
      </Link>

      {token ? (
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <Avatar sx={{ bgcolor: "black" }}>{avatarLetter}</Avatar>
          <Button
            variant="contained"
            onClick={handleLogout}
            sx={{ bgcolor: "black", "&:hover": { bgcolor: "#333" } }}
          >
            Logout
          </Button>
        </div>
      ) : (
        <div style={{ display: "flex", gap: 12 }}>
          <Button onClick={() => navigate("/login")}>Login</Button>
          <Button onClick={() => navigate("/register")}>Signup</Button>
        </div>
      )}
    </nav>
  );
}
